mapper.select:
SELECT round(AVG(netLink.FLOW_LINK),0) as flowLink, netLink.TIME as time
FROM TBL_DOMAIN_FLOW_LINK_STAT netLink , ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DRX_VM}  drxVm
WHERE netLink.DOMAIN_ID=drxVm.domain_id AND drxVm.drx_business_id=${drxbId}
AND netLink.TIME BETWEEN ${startTime} AND ${endTime}
GROUP BY TIME
ORDER BY TIME ASC

SELECT FLOW_LINK as flowLink, TIME as time, DOMAIN_ID as domainId FROM TBL_DOMAIN_FLOW_LINK_STAT
WHERE TIME = (SELECT MAX(TIME)-${duration} FROM TBL_DOMAIN_FLOW_LINK_STAT)

    AND DOMAIN_ID=${domainId}


    AND HOST_ID=${hostId}


    AND CLUSTER_ID=${clusterId}


    AND HOST_POOL_ID=${hostPoolId}

SELECT DOMAIN_ID as domainId,ROUND(AVG(FLOW_LINK),0) as flowLink FROM TBL_DOMAIN_FLOW_LINK_STAT WHERE DOMAIN_ID=${domainId}
AND TIME >= (SELECT MAX(TIME) FROM TBL_DOMAIN_FLOW_LINK_STAT WHERE DOMAIN_ID = ${domainId})-${duration}
GROUP BY DOMAIN_ID
